import{_ as s,c as a,d as e,o as t}from"./app-ClFPPuY-.js";const p={};function l(i,n){return t(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="基于-taro-的-headless-cms-多端前端架构-技术解析与二次开发导引" tabindex="-1"><a class="header-anchor" href="#基于-taro-的-headless-cms-多端前端架构-技术解析与二次开发导引"><span>基于 Taro 的 Headless CMS 多端前端架构：技术解析与二次开发导引</span></a></h1><blockquote><p>本文面向希望基于此项目进行二次开发的前端工程师，从技术栈选型、核心架构设计、关键模块实现到二开实践路径，提供一份完整的技术地图。</p></blockquote><hr><h2 id="一、技术栈总览" tabindex="-1"><a class="header-anchor" href="#一、技术栈总览"><span>一、技术栈总览</span></a></h2><p>本项目是一个 <strong>Taro 多端</strong> CMS 内容展示前端，一套代码同时编译为 H5、微信/支付宝/抖音小程序等多端应用：</p><table><thead><tr><th>层面</th><th>技术</th><th>版本</th><th>用途</th></tr></thead><tbody><tr><td>框架</td><td>Taro</td><td>4.1.x</td><td>多端统一框架</td></tr><tr><td>UI 库</td><td>React</td><td>18.x</td><td>视图层</td></tr><tr><td>语言</td><td>TypeScript</td><td>5.x</td><td>类型安全</td></tr><tr><td>构建</td><td>Vite</td><td>4.x</td><td>编译打包</td></tr><tr><td>样式</td><td>Tailwind CSS</td><td>3.x</td><td>原子化 CSS</td></tr><tr><td>小程序适配</td><td>weapp-tailwindcss</td><td>4.x</td><td>小程序端 Tailwind rem→rpx 转换</td></tr><tr><td>状态管理</td><td>Zustand</td><td>5.x</td><td>轻量响应式 Store（Context 模式）</td></tr><tr><td>数据层</td><td>TanStack React Query</td><td>5.x</td><td>服务端状态管理</td></tr><tr><td>国际化</td><td>i18next + react-i18next</td><td>25.x / 16.x</td><td>多语言翻译</td></tr><tr><td>HTTP 客户端</td><td>Axios</td><td>1.x</td><td>REST 通信</td></tr><tr><td>代码高亮</td><td>highlight.js</td><td>11.x</td><td>语法着色</td></tr><tr><td>Markdown</td><td>marked</td><td>17.x</td><td>内容解析</td></tr><tr><td>数学公式</td><td>KaTeX</td><td>0.16.x</td><td>LaTeX 渲染</td></tr><tr><td>流程图</td><td>Mermaid</td><td>11.x</td><td>图表渲染</td></tr><tr><td>实时通信</td><td>SSE (fetch-event-source)</td><td>2.x</td><td>服务端推送</td></tr></tbody></table><p><strong>包管理器：</strong> pnpm</p><hr><h2 id="二、核心架构设计" tabindex="-1"><a class="header-anchor" href="#二、核心架构设计"><span>二、核心架构设计</span></a></h2><h3 id="_2-1-多端编译模式" tabindex="-1"><a class="header-anchor" href="#_2-1-多端编译模式"><span>2.1 多端编译模式</span></a></h3><p>项目基于 Taro v4，通过 <code>@tarojs/cli</code> 将同一份 React 代码编译为多端产物：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># H5 开发</span></span>
<span class="line"><span class="token function">pnpm</span> dev:h5</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 微信小程序开发</span></span>
<span class="line"><span class="token function">pnpm</span> dev:weapp</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 构建产物</span></span>
<span class="line"><span class="token function">pnpm</span> build:h5     <span class="token comment"># → dist/ (SPA)</span></span>
<span class="line"><span class="token function">pnpm</span> build:weapp  <span class="token comment"># → dist/ (小程序包)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Taro 配置要点</strong>（<code>config/index.ts</code>）：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token generic-function"><span class="token function">defineConfig</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token string">&#39;vite&#39;</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token keyword">async</span> <span class="token punctuation">(</span>merge<span class="token punctuation">,</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">  framework<span class="token operator">:</span> <span class="token string">&#39;react&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  compiler<span class="token operator">:</span> <span class="token string">&#39;vite&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  designWidth<span class="token operator">:</span> <span class="token number">750</span><span class="token punctuation">,</span>       <span class="token comment">// 设计稿 750px，rpx 单位基准</span></span>
<span class="line">  sourceRoot<span class="token operator">:</span> <span class="token string">&#39;src&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  outputRoot<span class="token operator">:</span> <span class="token string">&#39;dist&#39;</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">  <span class="token comment">// H5 路由：browser mode + customRoutes（美化 URL）</span></span>
<span class="line">  h5<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    router<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      mode<span class="token operator">:</span> <span class="token string">&#39;browser&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      customRoutes<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token string-property property">&#39;pages/index/index&#39;</span><span class="token operator">:</span> <span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>           <span class="token comment">// 首页 → /</span></span>
<span class="line">        <span class="token string-property property">&#39;pages/post/detail/index&#39;</span><span class="token operator">:</span> <span class="token string">&#39;/post/detail&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token comment">// ... 更多路由映射</span></span>
<span class="line">      <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"></span>
<span class="line">  <span class="token comment">// 小程序端：注入 weapp-tailwindcss rem→rpx 转换</span></span>
<span class="line">  <span class="token function">modifyViteConfig</span><span class="token punctuation">(</span>config<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>process<span class="token punctuation">.</span>env<span class="token punctuation">.</span><span class="token constant">TARO_ENV</span> <span class="token operator">===</span> <span class="token string">&#39;weapp&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">      config<span class="token punctuation">.</span>plugins<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token function">UnifiedViteWeappTailwindcssPlugin</span><span class="token punctuation">(</span><span class="token punctuation">{</span> rem2rpx<span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>customRoutes 机制</strong>：Taro 内部页面路径如 <code>/pages/post/detail/index</code> 会映射为浏览器友好的短路径 <code>/post/detail</code>，使 H5 端 URL 更加简洁。</p><h3 id="_2-2-多端路由架构" tabindex="-1"><a class="header-anchor" href="#_2-2-多端路由架构"><span>2.2 多端路由架构</span></a></h3><p>Taro 使用<strong>页面栈</strong>路由模型，不同于 Next.js 的文件路由：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">src/pages/</span>
<span class="line">├── index/index.tsx              # 首页（pages 配置的第一项）</span>
<span class="line">├── post/</span>
<span class="line">│   ├── index/index.tsx          # 文章列表</span>
<span class="line">│   └── detail/index.tsx         # 文章详情（接收 ?id=xxx 参数）</span>
<span class="line">├── category/</span>
<span class="line">│   ├── index/index.tsx          # 分类列表</span>
<span class="line">│   └── detail/index.tsx         # 分类详情（接收 ?id=xxx 参数）</span>
<span class="line">├── tag/</span>
<span class="line">│   ├── index/index.tsx          # 标签列表</span>
<span class="line">│   └── detail/index.tsx         # 标签详情（接收 ?id=xxx 参数）</span>
<span class="line">├── about/index.tsx              # 关于页</span>
<span class="line">├── settings/index.tsx           # 设置</span>
<span class="line">├── user/index.tsx               # 用户中心</span>
<span class="line">└── ...                          # 其他页面</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>页面注册</strong>（<code>app.config.ts</code>）：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token function">defineAppConfig</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">  pages<span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token string">&#39;pages/index&#39;</span><span class="token punctuation">,</span>              <span class="token comment">// 首页（第一个为启动页）</span></span>
<span class="line">    <span class="token string">&#39;pages/category/index&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&#39;pages/category/detail/index&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&#39;pages/post/index&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&#39;pages/post/detail/index&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line">  <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">  window<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    navigationBarBackgroundColor<span class="token operator">:</span> <span class="token string">&#39;#fff&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    navigationBarTitleText<span class="token operator">:</span> <span class="token string">&#39;Taro CMS&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>路由导航</strong>（<code>useI18nRouter</code>）：</p><p>由于 Taro 不使用 locale 前缀路由（与 Next.js 版不同），提供了 <code>useI18nRouter</code> Hook 封装 Taro 路由 API：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">const</span> router <span class="token operator">=</span> <span class="token function">useI18nRouter</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 短路径自动转换为 Taro 内部路径</span></span>
<span class="line">router<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>                    <span class="token comment">// → Taro.navigateTo(&#39;/pages/index/index&#39;)</span></span>
<span class="line">router<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token string">&#39;/post/123&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>            <span class="token comment">// → Taro.navigateTo(&#39;/pages/post/detail/index?id=123&#39;)</span></span>
<span class="line">router<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token string">&#39;/category/detail?id=5&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">// → Taro.navigateTo(&#39;/pages/category/detail/index?id=5&#39;)</span></span>
<span class="line">router<span class="token punctuation">.</span><span class="token function">back</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>                       <span class="token comment">// → Taro.navigateBack()</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>页面刷新机制</strong>：Taro 页面使用 <code>useDidShow</code> 生命周期（而非 <code>useEffect</code>）监听页面显示，确保从子页面返回时也能刷新数据：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">Home</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> <span class="token punctuation">[</span>refreshKey<span class="token punctuation">,</span> setRefreshKey<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">useState</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token function">useDidShow</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">setRefreshKey</span><span class="token punctuation">(</span>prev <span class="token operator">=&gt;</span> prev <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 每次显示都刷新</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token operator">&lt;</span>View<span class="token operator">&gt;</span></span>
<span class="line">      <span class="token operator">&lt;</span>LatestPostsSection key<span class="token operator">=</span><span class="token punctuation">{</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">latest-</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>refreshKey<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">}</span> <span class="token operator">/</span><span class="token operator">&gt;</span></span>
<span class="line">      <span class="token operator">&lt;</span>CategoryListSection key<span class="token operator">=</span><span class="token punctuation">{</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">cat-</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>refreshKey<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">}</span> <span class="token operator">/</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span><span class="token operator">/</span>View<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-3-三层-api-架构" tabindex="-1"><a class="header-anchor" href="#_2-3-三层-api-架构"><span>2.3 三层 API 架构</span></a></h3><p>API 层遵循<strong>生成层 → 服务层 → Hook 层</strong>的三层分离架构：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">src/api/</span>
<span class="line">├── generated/          # [自动生成] protoc-gen-typescript-http 产出</span>
<span class="line">├── service/            # [服务封装] 业务逻辑、参数转换、单例管理</span>
<span class="line">├── hooks/              # [React Hook] useMutation/useQuery 封装 + 辅助函数</span>
<span class="line">└── index.ts            # 统一导出</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第一层 — 自动生成的客户端</strong>（<code>generated/</code>）：由 protobuf 定义自动生成的 HTTP 客户端代码，不应手动编辑。</p><p><strong>第二层 — 服务封装</strong>（<code>service/</code>）：基于生成的客户端封装业务方法，注入 locale、分页参数等：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// service/post.ts</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">listPostsRaw</span><span class="token punctuation">(</span>params<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">const</span> locale <span class="token operator">=</span> <span class="token function">currentLocaleLanguageCode</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">const</span> formValues <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token operator">...</span><span class="token punctuation">(</span>params<span class="token punctuation">.</span>formValues <span class="token operator">||</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span> locale<span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token function">getPostService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">List</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">        query<span class="token operator">:</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>formValues<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        page<span class="token operator">:</span> params<span class="token punctuation">.</span>paging<span class="token operator">?.</span>page<span class="token punctuation">,</span></span>
<span class="line">        pageSize<span class="token operator">:</span> params<span class="token punctuation">.</span>paging<span class="token operator">?.</span>pageSize<span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第三层 — React Hook</strong>（<code>hooks/</code>）：封装为 <code>useMutation</code> / <code>useQuery</code> Hook 和纯函数 <code>fetch*</code> 两种形态：</p><ul><li><code>useListPosts()</code> — 组件内使用的 React Hook</li><li><code>fetchListPosts()</code> — Store / 非 React 上下文中使用的纯异步函数</li></ul><p>每层职责清晰，二开时只需关注 service 和 hooks 层。</p><h3 id="_2-4-requestclient-—-http-通信内核" tabindex="-1"><a class="header-anchor" href="#_2-4-requestclient-—-http-通信内核"><span>2.4 RequestClient — HTTP 通信内核</span></a></h3><p><code>RequestClient</code> 是基于 Axios 封装的全局单例，通过拦截器链实现完整的认证生命周期：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">请求拦截链：Token 注入 → Request-ID 注入 → Locale 注入</span>
<span class="line">响应拦截链：数据解构 → 401 认证处理 → 错误消息提取</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>关键特性：</strong></p><ul><li><strong>Token 自动刷新</strong>：401 时自动调用 refresh token 接口，刷新期间后续请求排队等待</li><li><strong>请求重认证</strong>：刷新失败时清除凭证并重定向至登录页</li><li><strong>语言感知</strong>：自动注入 <code>Accept-Language</code> 头</li></ul><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// 初始化（在 StoreProvider 中执行）</span></span>
<span class="line">RequestClient<span class="token punctuation">.</span><span class="token function">init</span><span class="token punctuation">(</span>env<span class="token punctuation">.</span>apiBaseUrl<span class="token punctuation">,</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token function-variable function">getToken</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> accessStore<span class="token punctuation">.</span><span class="token function">getState</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>accessToken<span class="token operator">?.</span>value<span class="token punctuation">,</span></span>
<span class="line">  <span class="token function-variable function">getLocale</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> preferencesStore<span class="token punctuation">.</span><span class="token function">getState</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>preferences<span class="token punctuation">.</span>app<span class="token punctuation">.</span>locale<span class="token punctuation">,</span></span>
<span class="line">  <span class="token function-variable function">refreshToken</span><span class="token operator">:</span> <span class="token keyword">async</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token function-variable function">onReAuthenticate</span><span class="token operator">:</span> <span class="token keyword">async</span> <span class="token punctuation">(</span>redirect<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>二开时如需对接不同后端，只需修改 <code>StoreProvider</code> 中 <code>RequestClient.init()</code> 的回调参数。</p><h3 id="_2-5-状态管理-—-zustand-react-context" tabindex="-1"><a class="header-anchor" href="#_2-5-状态管理-—-zustand-react-context"><span>2.5 状态管理 — Zustand + React Context</span></a></h3><p>采用 Zustand 配合 React Context 的混合模式，避免全局单例在多实例场景下的数据泄漏：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">src/store/</span>
<span class="line">├── StoreProvider.tsx           # 聚合 Provider（创建所有 store 实例）</span>
<span class="line">└── core/</span>
<span class="line">    ├── access/                 # 认证凭证（accessToken、refreshToken）</span>
<span class="line">    ├── user/                   # 用户信息</span>
<span class="line">    └── loading/                # 全局加载状态</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>设计要点：</strong></p><ul><li>每个 Store 通过 <code>create*Store()</code> 工厂函数创建独立实例</li><li>通过 <code>useMemo</code> 确保 store 实例在组件生命周期内稳定</li><li>Context Provider 嵌套提供 store 给子树</li><li><code>RequestClient</code> 通过 <code>storeApi.getState()</code> 桥接 Context-based stores 到拦截器</li></ul><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// StoreProvider.tsx — 聚合所有 store 的 Provider</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">StoreProvider</span><span class="token punctuation">(</span><span class="token punctuation">{</span>children<span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> accessStore <span class="token operator">=</span> <span class="token function">useMemo</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">createAccessStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">const</span> userStore <span class="token operator">=</span> <span class="token function">useMemo</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">createUserStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">const</span> loadingStore <span class="token operator">=</span> <span class="token function">useMemo</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">createLoadingStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">const</span> preferencesStore <span class="token operator">=</span> <span class="token function">useMemo</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">createPreferencesStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token comment">// 初始化 RequestClient 拦截器</span></span>
<span class="line">  <span class="token function">useMemo</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>accessStore<span class="token punctuation">,</span> userStore<span class="token punctuation">,</span> preferencesStore<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token operator">&lt;</span>PreferencesStoreContext<span class="token punctuation">.</span>Provider value<span class="token operator">=</span><span class="token punctuation">{</span>preferencesStore<span class="token punctuation">}</span><span class="token operator">&gt;</span></span>
<span class="line">      <span class="token operator">&lt;</span>AccessStoreContext<span class="token punctuation">.</span>Provider value<span class="token operator">=</span><span class="token punctuation">{</span>accessStore<span class="token punctuation">}</span><span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span>UserStoreContext<span class="token punctuation">.</span>Provider value<span class="token operator">=</span><span class="token punctuation">{</span>userStore<span class="token punctuation">}</span><span class="token operator">&gt;</span></span>
<span class="line">          <span class="token operator">&lt;</span>LoadingStoreContext<span class="token punctuation">.</span>Provider value<span class="token operator">=</span><span class="token punctuation">{</span>loadingStore<span class="token punctuation">}</span><span class="token operator">&gt;</span></span>
<span class="line">            <span class="token punctuation">{</span>children<span class="token punctuation">}</span></span>
<span class="line">          <span class="token operator">&lt;</span><span class="token operator">/</span>LoadingStoreContext<span class="token punctuation">.</span>Provider<span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span><span class="token operator">/</span>UserStoreContext<span class="token punctuation">.</span>Provider<span class="token operator">&gt;</span></span>
<span class="line">      <span class="token operator">&lt;</span><span class="token operator">/</span>AccessStoreContext<span class="token punctuation">.</span>Provider<span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span><span class="token operator">/</span>PreferencesStoreContext<span class="token punctuation">.</span>Provider<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-6-偏好系统-—-preferences" tabindex="-1"><a class="header-anchor" href="#_2-6-偏好系统-—-preferences"><span>2.6 偏好系统 — Preferences</span></a></h3><p><code>core/preferences</code> 是一个独立的偏好管理模块，管理主题模式、语言、内容偏好、功能部件等用户配置：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">src/core/preferences/</span>
<span class="line">├── index.ts         # 统一导出（types + config + hooks + store）</span>
<span class="line">├── types/           # 类型定义（6 个分组：app/theme/content/copyright/widget/transition）</span>
<span class="line">├── config/          # 默认配置（defaultPreferences）</span>
<span class="line">├── store/           # Zustand Store（createPreferencesStore + Context）</span>
<span class="line">├── hooks/           # usePreferences / useThemeConfig / usePreferencesLocale</span>
<span class="line">└── utils/           # mergeDeep 深度合并工具</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>主题支持三种模式：<code>light</code>（亮色）、<code>dark</code>（暗色）、<code>auto</code>（跟随系统），通过内联 CSS 变量注入色板。</p><h3 id="_2-7-国际化体系" tabindex="-1"><a class="header-anchor" href="#_2-7-国际化体系"><span>2.7 国际化体系</span></a></h3><p>Taro 版使用 <strong>i18next + react-i18next</strong>（不同于 Next.js 版的 next-intl），不使用 URL 语言前缀路由：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// i18n/config.ts</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">const</span> locales <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;zh-CN&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;en-US&#39;</span><span class="token punctuation">]</span> <span class="token keyword">as</span> <span class="token keyword">const</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">const</span> defaultLocale <span class="token operator">=</span> <span class="token string">&#39;zh-CN&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 翻译文件扁平化后注入 i18next</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">getFlattenedMessages</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">:</span> Record<span class="token operator">&lt;</span>Locale<span class="token punctuation">,</span> Record<span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token punctuation">,</span> <span class="token builtin">string</span><span class="token operator">&gt;&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// 将 messages/zh-CN/*.json 所有文件合并为扁平键值对</span></span>
<span class="line">  <span class="token comment">// 如 { page: { home: { title: &#39;首页&#39; } } } → { &#39;page.home.title&#39;: &#39;首页&#39; }</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>翻译文件结构：</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">messages/</span>
<span class="line">├── zh-CN/</span>
<span class="line">│   ├── app.json           # 应用级文案</span>
<span class="line">│   ├── navbar.json         # 导航栏</span>
<span class="line">│   ├── page.json           # 页面文案</span>
<span class="line">│   ├── cms.json            # CMS 业务文案</span>
<span class="line">│   ├── authentication.json # 认证相关</span>
<span class="line">│   ├── comment.json        # 评论</span>
<span class="line">│   ├── enum.json           # 枚举翻译</span>
<span class="line">│   ├── settings.json       # 设置</span>
<span class="line">│   └── ...</span>
<span class="line">└── en-US/</span>
<span class="line">    └── ...（同构文件）</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>多语言内容获取</strong>：后端返回的实体（Post、Category 等）携带 <code>translations[]</code> 数组，前端通过辅助函数按当前 locale 提取对应翻译：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">getPostTitle</span><span class="token punctuation">(</span>post<span class="token operator">:</span> contentservicev1_Post<span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">const</span> translation <span class="token operator">=</span> <span class="token function">getTranslation</span><span class="token punctuation">(</span>post<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 匹配当前语言</span></span>
<span class="line">    <span class="token keyword">return</span> translation<span class="token operator">?.</span>title <span class="token operator">||</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="三、关键模块深度解析" tabindex="-1"><a class="header-anchor" href="#三、关键模块深度解析"><span>三、关键模块深度解析</span></a></h2><h3 id="_3-1-内容渲染管线" tabindex="-1"><a class="header-anchor" href="#_3-1-内容渲染管线"><span>3.1 内容渲染管线</span></a></h3><p><code>ContentViewer</code> 组件实现了一条完整的 Markdown → HTML 渲染管线：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">Markdown 源文</span>
<span class="line">  ↓ marked（自定义 Renderer）</span>
<span class="line">  ├── 代码块 → highlight.js 语法高亮</span>
<span class="line">  ├── 数学公式 → KaTeX 渲染（行内 + 块级）</span>
<span class="line">  ├── 流程图 → Mermaid 渲染</span>
<span class="line">  ├── 表格 → 响应式容器包装</span>
<span class="line">  ├── 图片 → figure/figcaption 语义化</span>
<span class="line">  └── 链接 → 外部链接自动新窗口</span>
<span class="line">  ↓ DOMPurify（XSS 清洗）</span>
<span class="line">  ↓ 安全 HTML 输出</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>安全策略</strong>：DOMPurify 白名单严格限制允许的标签和属性，防止 XSS 攻击。</p><h3 id="_3-2-主题系统" tabindex="-1"><a class="header-anchor" href="#_3-2-主题系统"><span>3.2 主题系统</span></a></h3><p>采用<strong>内联 CSS 变量</strong>注入方案（而非 CSS 文件定义），由 <code>ThemeClientProvider</code> 组件根据 <code>isDark</code> 状态动态切换色板：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// ThemeClientProvider.tsx</span></span>
<span class="line"><span class="token keyword">const</span> themeStyle <span class="token operator">=</span> <span class="token function">useMemo</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> <span class="token punctuation">(</span>isDark<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token string-property property">&#39;--color-text-main&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ffffffe6&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token string-property property">&#39;--color-text-sec&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ffffffcc&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token string-property property">&#39;--color-page-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#17171a&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token string-property property">&#39;--color-card-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#232326&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token string-property property">&#39;--color-split-line&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#3a3a3c&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token string-property property">&#39;--color-bar-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;rgba(35, 35, 38, 0.92)&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token string-property property">&#39;--color-text-main&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#1d2129&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string-property property">&#39;--color-text-sec&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#4e5969&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string-property property">&#39;--color-page-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ebedf0&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string-property property">&#39;--color-card-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ffffff&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string-property property">&#39;--color-split-line&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#e8eaed&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string-property property">&#39;--color-bar-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;rgba(255, 255, 255, 0.92)&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>isDark<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">return</span> <span class="token operator">&lt;</span>View style<span class="token operator">=</span><span class="token punctuation">{</span>themeStyle<span class="token punctuation">}</span><span class="token operator">&gt;</span><span class="token punctuation">{</span>children<span class="token punctuation">}</span><span class="token operator">&lt;</span><span class="token operator">/</span>View<span class="token operator">&gt;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>设计要点：</strong></p><ul><li><strong>全平台兼容</strong>：内联 CSS 变量方案在 H5 和小程序端均可靠工作</li><li><strong>暗色模式检测</strong>：H5 端监听 <code>window.matchMedia(&#39;(prefers-color-scheme: dark)&#39;)</code></li><li><strong>亮色/暗色类切换</strong>：H5 端在 <code>&lt;html&gt;</code> 上切换 <code>.dark</code> / <code>.light</code> class，小程序端使用 <code>page.dark</code> 选择器</li><li><strong>CSS 变量与 Tailwind 映射</strong>：<code>--color-text-main</code> → <code>text-textMain</code>，<code>--color-page-bg</code> → <code>bg-pageBg</code></li></ul><h3 id="_3-3-布局系统" tabindex="-1"><a class="header-anchor" href="#_3-3-布局系统"><span>3.3 布局系统</span></a></h3><p><code>Layout</code> 组件是所有页面的外层容器，统一提供 Header、Footer、BackToTop、NavigationProgress：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// Layout.tsx</span></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">Layout</span><span class="token punctuation">(</span><span class="token punctuation">{</span>children<span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token operator">&lt;</span>ThemeClientProvider<span class="token operator">&gt;</span></span>
<span class="line">      <span class="token operator">&lt;</span>MobileNavProvider<span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span>NavigationProgress <span class="token operator">/</span><span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span>Header <span class="token operator">/</span><span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span>View className<span class="token operator">=</span><span class="token string">&#39;min-h-screen pt-[88rpx]&#39;</span><span class="token operator">&gt;</span></span>
<span class="line">          <span class="token punctuation">{</span>children<span class="token punctuation">}</span></span>
<span class="line">        <span class="token operator">&lt;</span><span class="token operator">/</span>View<span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span>Footer <span class="token operator">/</span><span class="token operator">&gt;</span></span>
<span class="line">        <span class="token operator">&lt;</span>BackToTop <span class="token operator">/</span><span class="token operator">&gt;</span></span>
<span class="line">      <span class="token operator">&lt;</span><span class="token operator">/</span>MobileNavProvider<span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span><span class="token operator">/</span>ThemeClientProvider<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>应用入口</strong>（<code>app.ts</code>）：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">function</span> <span class="token function">App</span><span class="token punctuation">(</span><span class="token punctuation">{</span>children<span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token function">useLaunch</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span> <span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;App launched.&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token function">createElement</span><span class="token punctuation">(</span></span>
<span class="line">    StoreProvider<span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token function">createElement</span><span class="token punctuation">(</span>Layout<span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">,</span> children<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>层级关系：<code>App → StoreProvider → Layout (ThemeClientProvider → MobileNavProvider → Header/Footer/Content)</code></p><h3 id="_3-4-认证流程" tabindex="-1"><a class="header-anchor" href="#_3-4-认证流程"><span>3.4 认证流程</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">用户登录 → 存储 accessToken + refreshToken（Zustand Store + AES 加密持久化）</span>
<span class="line">    ↓</span>
<span class="line">每次请求 → Token 拦截器注入 Authorization 头</span>
<span class="line">    ↓</span>
<span class="line">401 响应 → 自动调用 refreshToken 接口</span>
<span class="line">    ↓ 成功               ↓ 失败</span>
<span class="line">更新 Token 继续请求    清除凭证 → Taro.redirectTo 用户页</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Token 存储在 Zustand Store 中（内存态），通过 AES 加密后持久化到 localStorage，实现「刷新页面不丢失登录态」。</p><h3 id="_3-5-评论系统" tabindex="-1"><a class="header-anchor" href="#_3-5-评论系统"><span>3.5 评论系统</span></a></h3><p>评论模块支持多级嵌套回复，包含：</p><ul><li><strong>评论列表</strong>（<code>CommentTree</code>）：树形结构展示，博主回复标签高亮</li><li><strong>评论输入</strong>（<code>CommentSection</code>）：支持回复指定评论，暗黑模式适配</li><li><strong>SSE 实时推送</strong>：新评论通过 Server-Sent Events 实时通知</li></ul><hr><h2 id="四、项目目录结构与职责" tabindex="-1"><a class="header-anchor" href="#四、项目目录结构与职责"><span>四、项目目录结构与职责</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">src/</span>
<span class="line">├── api/                    # API 三层架构</span>
<span class="line">│   ├── generated/          #   自动生成的客户端代码</span>
<span class="line">│   ├── service/            #   业务服务封装</span>
<span class="line">│   └── hooks/              #   React Hook + 辅助函数</span>
<span class="line">├── app.config.ts           # Taro 页面注册 + 全局窗口配置</span>
<span class="line">├── app.ts                  # 应用入口（StoreProvider + Layout）</span>
<span class="line">├── assets/                 # 静态资源</span>
<span class="line">│   ├── fonts/              #   字体文件</span>
<span class="line">│   ├── icons/              #   图标</span>
<span class="line">│   └── images/             #   图片（logo 等）</span>
<span class="line">├── components/             # UI 组件</span>
<span class="line">│   ├── layout/             #   布局组件（Header、Footer、MobileNav、BackToTop、ThemeClientProvider）</span>
<span class="line">│   ├── category/           #   分类组件（Card、List、Filter、Tree）</span>
<span class="line">│   ├── comment/            #   评论组件（CommentSection、CommentTree）</span>
<span class="line">│   ├── content/            #   内容渲染器（ContentViewer）</span>
<span class="line">│   ├── post/               #   文章组件（PostCard、PostList）</span>
<span class="line">│   ├── Pagination/         #   分页组件</span>
<span class="line">│   ├── otp-input/          #   验证码输入组件</span>
<span class="line">│   └── ui/                 #   基础 UI 组件（AppEmpty、Button、Input）</span>
<span class="line">├── config/                 # 环境变量配置（env.ts）</span>
<span class="line">├── core/                   # 核心基础设施</span>
<span class="line">│   ├── preferences/        #   偏好系统（主题、语言、内容偏好、部件开关）</span>
<span class="line">│   ├── storage/            #   存储抽象（localStorage 封装 + AES 加密）</span>
<span class="line">│   ├── transport/          #   通信层</span>
<span class="line">│   │   ├── rest/           #     REST（RequestClient）</span>
<span class="line">│   │   └── sse/            #     SSE（实时推送）</span>
<span class="line">│   └── query-client.ts     #   React Query 全局配置</span>
<span class="line">├── hooks/                  # 通用自定义 Hook</span>
<span class="line">├── i18n/                   # 国际化配置与工具</span>
<span class="line">│   ├── config.ts           #   语言定义 + 翻译资源</span>
<span class="line">│   ├── index.ts            #   i18next 初始化</span>
<span class="line">│   └── helpers/            #   useI18nRouter 路由 Hook</span>
<span class="line">├── lib/                    # 工具库（next-intl-compat、cn 等）</span>
<span class="line">├── pages/                  # Taro 页面</span>
<span class="line">│   ├── index/              #   首页</span>
<span class="line">│   ├── post/               #   文章（列表 + 详情）</span>
<span class="line">│   ├── category/           #   分类（列表 + 详情）</span>
<span class="line">│   ├── tag/                #   标签（列表 + 详情）</span>
<span class="line">│   ├── about/              #   关于</span>
<span class="line">│   ├── login/              #   登录</span>
<span class="line">│   ├── register/           #   注册</span>
<span class="line">│   ├── settings/           #   设置</span>
<span class="line">│   ├── user/               #   用户中心</span>
<span class="line">│   └── ...                 #   其他页面</span>
<span class="line">├── plugins/                # 插件（XIcon 图标组件）</span>
<span class="line">├── store/                  # Zustand Store（Provider 模式）</span>
<span class="line">│   ├── StoreProvider.tsx   #   聚合 Provider</span>
<span class="line">│   └── core/               #   access / user / loading</span>
<span class="line">└── utils/                  # 通用工具函数</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="五、二次开发导引" tabindex="-1"><a class="header-anchor" href="#五、二次开发导引"><span>五、二次开发导引</span></a></h2><h3 id="_5-1-环境搭建" tabindex="-1"><a class="header-anchor" href="#_5-1-环境搭建"><span>5.1 环境搭建</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># 安装依赖</span></span>
<span class="line"><span class="token function">pnpm</span> <span class="token function">install</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 启动 H5 开发服务器</span></span>
<span class="line"><span class="token function">pnpm</span> dev:h5</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 启动微信小程序开发</span></span>
<span class="line"><span class="token function">pnpm</span> dev:weapp</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 构建 H5 生产产物（输出到 dist/）</span></span>
<span class="line"><span class="token function">pnpm</span> build:h5</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 构建微信小程序生产产物</span></span>
<span class="line"><span class="token function">pnpm</span> build:weapp</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 类型检查</span></span>
<span class="line"><span class="token function">pnpm</span> lint</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>环境变量配置</strong>（<code>.env.development</code>）：</p><div class="language-env line-numbers-mode" data-highlighter="prismjs" data-ext="env"><pre><code><span class="line">TARO_APP_NAMESPACE=gowind-cms-app            # 应用命名空间</span>
<span class="line">TARO_APP_API_BASE_URL=https://api.cms.gowind.cloud  # 后端 API 地址</span>
<span class="line">TARO_APP_AES_KEY=&quot;f51d66a73d8a0927&quot;           # AES 加密密钥</span>
<span class="line">TARO_APP_TITLE=&#39;GoWind Content Hub&#39;           # 应用标题</span>
<span class="line">TARO_DEFAULT_LOCALE=zh-CN                     # 默认语言</span>
<span class="line">TARO_ENABLE_MOCK=false                        # 是否启用 Mock</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>环境变量通过 <code>config/index.ts</code> 的 <code>defineConstants</code> 注入到客户端代码，在 <code>src/config/env.ts</code> 中统一导出。</p></blockquote><h3 id="_5-2-新增一个业务页面" tabindex="-1"><a class="header-anchor" href="#_5-2-新增一个业务页面"><span>5.2 新增一个业务页面</span></a></h3><p>以「产品」模块为例：</p><p><strong>Step 1 — 封装服务层</strong></p><p>创建 <code>api/service/product.ts</code>：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> requestApi <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/core&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">listProducts</span><span class="token punctuation">(</span>params<span class="token operator">:</span> <span class="token punctuation">{</span> page<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">;</span> pageSize<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">number</span> <span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> requestApi<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;/api/v1/products&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> params <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Step 2 — 封装 Hook 层</strong></p><p>创建 <code>api/hooks/product.ts</code>：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> useMutation <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@tanstack/react-query&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> listProducts <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/api/service/product&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">useListProducts</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token function">useMutation</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token function-variable function">mutationFn</span><span class="token operator">:</span> <span class="token punctuation">(</span>params<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">listProducts</span><span class="token punctuation">(</span>params<span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Step 3 — 创建页面</strong></p><p>创建 <code>src/pages/product/index.tsx</code>：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span>View<span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@tarojs/components&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span>useListProducts<span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/api/hooks/product&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">ProductPage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">const</span> <span class="token punctuation">{</span>mutate<span class="token operator">:</span> fetchProducts<span class="token punctuation">,</span> data<span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">useListProducts</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Step 4 — 注册页面路由</strong></p><p>在 <code>app.config.ts</code> 中添加：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token function">defineAppConfig</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">  pages<span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token string">&#39;pages/index&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line">    <span class="token string">&#39;pages/product/index&#39;</span><span class="token punctuation">,</span>    <span class="token comment">// 新增</span></span>
<span class="line">  <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 <code>config/index.ts</code> 的 <code>h5.router.customRoutes</code> 中添加 H5 美化路由：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line">customRoutes<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// ...</span></span>
<span class="line">  <span class="token string-property property">&#39;pages/product/index&#39;</span><span class="token operator">:</span> <span class="token string">&#39;/product&#39;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Step 5 — 添加导航入口</strong></p><p>在 <code>components/layout/MobileNav.tsx</code> 的导航菜单中添加产品页入口。</p><h3 id="_5-3-新增一种语言" tabindex="-1"><a class="header-anchor" href="#_5-3-新增一种语言"><span>5.3 新增一种语言</span></a></h3><p><strong>Step 1 — 创建翻译文件</strong></p><p>在 <code>messages/</code> 下创建新语言目录（如 <code>ja-JP/</code>），复制现有 JSON 文件并翻译。</p><p><strong>Step 2 — 注册语言</strong></p><p>在 <code>i18n/config.ts</code> 中：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// 1. 导入翻译文件</span></span>
<span class="line"><span class="token keyword">import</span> jaJP_app <span class="token keyword">from</span> <span class="token string">&#39;../../messages/ja-JP/app.json&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// ... 其他文件</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 2. 添加到 locales 数组</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">const</span> locales <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;zh-CN&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;en-US&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;ja-JP&#39;</span><span class="token punctuation">]</span> <span class="token keyword">as</span> <span class="token keyword">const</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 3. 添加到 allMessages 对象</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">const</span> allMessages <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token string-property property">&#39;zh-CN&#39;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;en-US&#39;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;ja-JP&#39;</span><span class="token operator">:</span> <span class="token punctuation">{</span> app<span class="token operator">:</span> jaJP_app<span class="token punctuation">,</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Step 3 — 更新类型定义</strong></p><p>在 <code>core/preferences/types/layout.ts</code> 中扩展 <code>SupportedLanguagesType</code>：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">export</span> <span class="token keyword">type</span> <span class="token class-name">SupportedLanguagesType</span> <span class="token operator">=</span> <span class="token string">&#39;zh-CN&#39;</span> <span class="token operator">|</span> <span class="token string">&#39;en-US&#39;</span> <span class="token operator">|</span> <span class="token string">&#39;ja-JP&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_5-4-自定义主题配色" tabindex="-1"><a class="header-anchor" href="#_5-4-自定义主题配色"><span>5.4 自定义主题配色</span></a></h3><p>修改 <code>ThemeClientProvider.tsx</code> 中的 CSS 变量色板即可：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// 亮色色板</span></span>
<span class="line"><span class="token keyword">const</span> lightTheme <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-text-main&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#1d2129&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-page-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ebedf0&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-card-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ffffff&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-split-line&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#e8eaed&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 暗色色板</span></span>
<span class="line"><span class="token keyword">const</span> darkTheme <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-text-main&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#ffffffe6&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-page-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#17171a&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-card-bg&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#232326&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token string-property property">&#39;--color-split-line&#39;</span><span class="token operator">:</span> <span class="token string">&#39;#3a3a3c&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>所有使用 <code>bg-pageBg</code>、<code>bg-cardBg</code>、<code>text-textMain</code> 等 Tailwind 类的组件会自动跟随变化。</p><h3 id="_5-5-对接不同后端" tabindex="-1"><a class="header-anchor" href="#_5-5-对接不同后端"><span>5.5 对接不同后端</span></a></h3><p>本项目前端与后端通过 REST API 通信，对接不同后端的核心修改点：</p><ol><li><strong><code>config/env.ts</code></strong> / <strong><code>.env.development</code></strong> — 修改 <code>TARO_APP_API_BASE_URL</code></li><li><strong><code>api/service/*.ts</code></strong> — 调整请求参数格式和响应结构</li><li><strong><code>api/hooks/*.ts</code></strong> — 调整类型定义</li><li><strong><code>api/generated/</code></strong> — 如后端使用 protobuf，重新生成；否则手动定义类型</li></ol><p>认证流程可通过修改 <code>StoreProvider.tsx</code> 中 <code>RequestClient.init()</code> 的回调来自定义。</p><h3 id="_5-6-部署" tabindex="-1"><a class="header-anchor" href="#_5-6-部署"><span>5.6 部署</span></a></h3><p><strong>H5 部署：</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">pnpm</span> build:h5   <span class="token comment"># 输出到 dist/</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>产物为 SPA 静态文件，需配置服务器 fallback 到 <code>index.html</code>。</p><p><strong>Nginx 配置示例：</strong></p><div class="language-nginx line-numbers-mode" data-highlighter="prismjs" data-ext="nginx"><pre><code><span class="line"><span class="token directive"><span class="token keyword">server</span></span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">listen</span> <span class="token number">80</span></span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">root</span> /var/www/cms</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token directive"><span class="token keyword">index</span> index.html</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token directive"><span class="token keyword">location</span> /</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token directive"><span class="token keyword">try_files</span> <span class="token variable">$uri</span> <span class="token variable">$uri</span>/ /index.html</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>微信小程序部署：</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">pnpm</span> build:weapp   <span class="token comment"># 输出到 dist/</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将 <code>dist/</code> 目录上传到微信开发者工具即可预览和发布。</p><hr><h2 id="六、开发规范与注意事项" tabindex="-1"><a class="header-anchor" href="#六、开发规范与注意事项"><span>六、开发规范与注意事项</span></a></h2><h3 id="_6-1-taro-组件限制" tabindex="-1"><a class="header-anchor" href="#_6-1-taro-组件限制"><span>6.1 Taro 组件限制</span></a></h3><p>Taro 使用 <code>&lt;View&gt;</code>、<code>&lt;Text&gt;</code>、<code>&lt;Image&gt;</code> 等跨端组件替代 HTML 标签：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code><span class="line"><span class="token comment">// ✅ 正确（跨端兼容）</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">View</span></span> <span class="token attr-name">className</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&#39;</span>flex items-center<span class="token punctuation">&#39;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">  </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">Text</span></span> <span class="token attr-name">className</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&#39;</span>text-textMain<span class="token punctuation">&#39;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">标题</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">Text</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">  </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">Image</span></span> <span class="token attr-name">src</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>logo<span class="token punctuation">}</span></span> <span class="token attr-name">mode</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&#39;</span>aspectFit<span class="token punctuation">&#39;</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">View</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ❌ 错误（小程序不支持）</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">className</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&#39;</span>flex items-center<span class="token punctuation">&#39;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">  </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span><span class="token punctuation">&gt;</span></span><span class="token plain-text">标题</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">  </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>img</span> <span class="token attr-name">src</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>logo<span class="token punctuation">}</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-2-rpx-单位" tabindex="-1"><a class="header-anchor" href="#_6-2-rpx-单位"><span>6.2 rpx 单位</span></a></h3><p>设计稿基于 750px 宽度，使用 <code>rpx</code> 单位确保多端自适应：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">View</span></span> <span class="token attr-name">className</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&#39;</span>px-[24rpx] pt-[32rpx]<span class="token punctuation">&#39;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">  </span><span class="token punctuation">{</span><span class="token comment">/* 内边距使用 rpx */</span><span class="token punctuation">}</span><span class="token plain-text"></span>
<span class="line">  </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">Text</span></span> <span class="token attr-name">className</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&#39;</span>text-[28rpx]<span class="token punctuation">&#39;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">文字</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">Text</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">  </span><span class="token punctuation">{</span><span class="token comment">/* 字号使用 rpx */</span><span class="token punctuation">}</span><span class="token plain-text"></span>
<span class="line"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">View</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Tailwind CSS 中使用方括号语法（如 <code>px-[24rpx]</code>）指定 rpx 值。</p><h3 id="_6-3-api-hooks-双形态" tabindex="-1"><a class="header-anchor" href="#_6-3-api-hooks-双形态"><span>6.3 API Hooks 双形态</span></a></h3><p>每个业务实体通常提供两种调用形态：</p><ul><li><strong>Hook 形态</strong>（<code>use*</code>）— 用于 React 组件内</li><li><strong>纯函数形态</strong>（<code>fetch*</code>）— 用于 Store、事件处理等非 React 上下文</li></ul><h3 id="_6-4-多语言内容辅助函数" tabindex="-1"><a class="header-anchor" href="#_6-4-多语言内容辅助函数"><span>6.4 多语言内容辅助函数</span></a></h3><p>获取后端实体的多语言字段时，使用 <code>hooks/</code> 中导出的辅助函数而非直接访问 <code>translations</code> 数组：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> getPostTitle<span class="token punctuation">,</span> getPostSummary<span class="token punctuation">,</span> getPostThumbnail <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/api/hooks&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">const</span> title <span class="token operator">=</span> <span class="token function">getPostTitle</span><span class="token punctuation">(</span>post<span class="token punctuation">)</span><span class="token punctuation">;</span>       <span class="token comment">// 自动匹配当前语言</span></span>
<span class="line"><span class="token keyword">const</span> summary <span class="token operator">=</span> <span class="token function">getPostSummary</span><span class="token punctuation">(</span>post<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-5-环境变量" tabindex="-1"><a class="header-anchor" href="#_6-5-环境变量"><span>6.5 环境变量</span></a></h3><p>Taro 环境变量必须以 <code>TARO_APP_</code> 前缀开头（Taro 规范），通过 <code>config/index.ts</code> 的 <code>defineConstants</code> 注入。修改 <code>.env</code> 文件后需重启开发服务器。</p><h3 id="_6-6-样式优先级" tabindex="-1"><a class="header-anchor" href="#_6-6-样式优先级"><span>6.6 样式优先级</span></a></h3><p>项目使用 Tailwind CSS + rpx 单位，自定义样式优先使用 Tailwind 类名。全局 CSS 样式在 <code>app.css</code> 中定义。</p><p><strong>H5 端特殊处理</strong>：Input / Textarea 组件的背景色和文字颜色需要通过全局 CSS <code>!important</code> 覆盖 Taro 默认样式，以确保暗黑模式正确显示。</p><h3 id="_6-7-路由注意事项" tabindex="-1"><a class="header-anchor" href="#_6-7-路由注意事项"><span>6.7 路由注意事项</span></a></h3><ul><li>使用 <code>useI18nRouter()</code> Hook 进行路由跳转，它会自动处理短路径到 Taro 内部路径的转换</li><li>H5 端回首页（<code>reLaunch</code>）使用 <code>window.location.href</code> 强制浏览器原生导航，因为 Taro 的 SPA 路由只做 <code>history.pushState</code> 不触发页面重渲染</li></ul><hr><h2 id="七、技术亮点总结" tabindex="-1"><a class="header-anchor" href="#七、技术亮点总结"><span>七、技术亮点总结</span></a></h2><ol><li><strong>一套代码多端运行</strong>：Taro 框架实现 H5 + 微信/支付宝/抖音小程序的统一代码库</li><li><strong>类型安全的 API 层</strong>：protobuf 自动生成 → 三层架构 → 完整 TypeScript 类型贯穿</li><li><strong>Tailwind CSS 多端适配</strong>：通过 weapp-tailwindcss 插件实现 rem→rpx 自动转换</li><li><strong>内联 CSS 变量主题系统</strong>：全平台兼容的暗色/亮色/自动主题切换</li><li><strong>Token 自动刷新</strong>：内置请求排队机制，刷新期间不丢失任何请求</li><li><strong>内容渲染管线</strong>：Markdown + 代码高亮 + 数学公式 + 流程图，一条管线处理多种内容格式</li><li><strong>Zustand + Context</strong>：工厂函数模式避免全局单例，Provider 嵌套保证 store 隔离</li><li><strong>i18next 国际化</strong>：翻译文件扁平化注入，语言切换无需 URL 前缀</li></ol><hr><blockquote><p><strong>快速开始</strong>：<code>pnpm install &amp;&amp; pnpm dev:h5</code>，打开 <code>http://localhost:10086</code> 即可运行。</p></blockquote><ul><li><strong>Github 开源仓库</strong>：<a href="https://github.com/tx7do/go-wind-cms" target="_blank" rel="noopener noreferrer">https://github.com/tx7do/go-wind-cms</a></li><li><strong>Gitee 开源仓库</strong>：<a href="https://gitee.com/tx7do/go-wind-cms" target="_blank" rel="noopener noreferrer">https://gitee.com/tx7do/go-wind-cms</a></li><li><strong>在线演示地址</strong>：<a href="https://taro.cms.gowind.cloud" target="_blank" rel="noopener noreferrer">https://taro.cms.gowind.cloud</a></li></ul>`,163)])])}const c=s(p,[["render",l]]),r=JSON.parse('{"path":"/posts/go-wind-cms-taro-tech-guide.html","title":"基于 Taro 的 Headless CMS 多端前端架构：技术解析与二次开发导引","lang":"zh-CN","frontmatter":{"date":"2026-06-04T00:00:00.000Z","category":["GoWind风行"],"tag":["Taro","React","CMS","GoWind"],"sticky":10},"headers":[{"level":2,"title":"一、技术栈总览","slug":"一、技术栈总览","link":"#一、技术栈总览","children":[]},{"level":2,"title":"二、核心架构设计","slug":"二、核心架构设计","link":"#二、核心架构设计","children":[{"level":3,"title":"2.1 多端编译模式","slug":"_2-1-多端编译模式","link":"#_2-1-多端编译模式","children":[]},{"level":3,"title":"2.2 多端路由架构","slug":"_2-2-多端路由架构","link":"#_2-2-多端路由架构","children":[]},{"level":3,"title":"2.3 三层 API 架构","slug":"_2-3-三层-api-架构","link":"#_2-3-三层-api-架构","children":[]},{"level":3,"title":"2.4 RequestClient — HTTP 通信内核","slug":"_2-4-requestclient-—-http-通信内核","link":"#_2-4-requestclient-—-http-通信内核","children":[]},{"level":3,"title":"2.5 状态管理 — Zustand + React Context","slug":"_2-5-状态管理-—-zustand-react-context","link":"#_2-5-状态管理-—-zustand-react-context","children":[]},{"level":3,"title":"2.6 偏好系统 — Preferences","slug":"_2-6-偏好系统-—-preferences","link":"#_2-6-偏好系统-—-preferences","children":[]},{"level":3,"title":"2.7 国际化体系","slug":"_2-7-国际化体系","link":"#_2-7-国际化体系","children":[]}]},{"level":2,"title":"三、关键模块深度解析","slug":"三、关键模块深度解析","link":"#三、关键模块深度解析","children":[{"level":3,"title":"3.1 内容渲染管线","slug":"_3-1-内容渲染管线","link":"#_3-1-内容渲染管线","children":[]},{"level":3,"title":"3.2 主题系统","slug":"_3-2-主题系统","link":"#_3-2-主题系统","children":[]},{"level":3,"title":"3.3 布局系统","slug":"_3-3-布局系统","link":"#_3-3-布局系统","children":[]},{"level":3,"title":"3.4 认证流程","slug":"_3-4-认证流程","link":"#_3-4-认证流程","children":[]},{"level":3,"title":"3.5 评论系统","slug":"_3-5-评论系统","link":"#_3-5-评论系统","children":[]}]},{"level":2,"title":"四、项目目录结构与职责","slug":"四、项目目录结构与职责","link":"#四、项目目录结构与职责","children":[]},{"level":2,"title":"五、二次开发导引","slug":"五、二次开发导引","link":"#五、二次开发导引","children":[{"level":3,"title":"5.1 环境搭建","slug":"_5-1-环境搭建","link":"#_5-1-环境搭建","children":[]},{"level":3,"title":"5.2 新增一个业务页面","slug":"_5-2-新增一个业务页面","link":"#_5-2-新增一个业务页面","children":[]},{"level":3,"title":"5.3 新增一种语言","slug":"_5-3-新增一种语言","link":"#_5-3-新增一种语言","children":[]},{"level":3,"title":"5.4 自定义主题配色","slug":"_5-4-自定义主题配色","link":"#_5-4-自定义主题配色","children":[]},{"level":3,"title":"5.5 对接不同后端","slug":"_5-5-对接不同后端","link":"#_5-5-对接不同后端","children":[]},{"level":3,"title":"5.6 部署","slug":"_5-6-部署","link":"#_5-6-部署","children":[]}]},{"level":2,"title":"六、开发规范与注意事项","slug":"六、开发规范与注意事项","link":"#六、开发规范与注意事项","children":[{"level":3,"title":"6.1 Taro 组件限制","slug":"_6-1-taro-组件限制","link":"#_6-1-taro-组件限制","children":[]},{"level":3,"title":"6.2 rpx 单位","slug":"_6-2-rpx-单位","link":"#_6-2-rpx-单位","children":[]},{"level":3,"title":"6.3 API Hooks 双形态","slug":"_6-3-api-hooks-双形态","link":"#_6-3-api-hooks-双形态","children":[]},{"level":3,"title":"6.4 多语言内容辅助函数","slug":"_6-4-多语言内容辅助函数","link":"#_6-4-多语言内容辅助函数","children":[]},{"level":3,"title":"6.5 环境变量","slug":"_6-5-环境变量","link":"#_6-5-环境变量","children":[]},{"level":3,"title":"6.6 样式优先级","slug":"_6-6-样式优先级","link":"#_6-6-样式优先级","children":[]},{"level":3,"title":"6.7 路由注意事项","slug":"_6-7-路由注意事项","link":"#_6-7-路由注意事项","children":[]}]},{"level":2,"title":"七、技术亮点总结","slug":"七、技术亮点总结","link":"#七、技术亮点总结","children":[]}],"git":{"updatedTime":1780577072000,"contributors":[{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":1,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"8287f26a5933598dbf72a16f0cd87738798ea2e7","time":1780577072000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add post."}]},"filePathRelative":"posts/go-wind-cms-taro-tech-guide.md","excerpt":"\\n<blockquote>\\n<p>本文面向希望基于此项目进行二次开发的前端工程师，从技术栈选型、核心架构设计、关键模块实现到二开实践路径，提供一份完整的技术地图。</p>\\n</blockquote>\\n<hr>\\n<h2>一、技术栈总览</h2>\\n<p>本项目是一个 <strong>Taro 多端</strong> CMS 内容展示前端，一套代码同时编译为 H5、微信/支付宝/抖音小程序等多端应用：</p>\\n<table>\\n<thead>\\n<tr>\\n<th>层面</th>\\n<th>技术</th>\\n<th>版本</th>\\n<th>用途</th>\\n</tr>\\n</thead>\\n<tbody>\\n<tr>\\n<td>框架</td>\\n<td>Taro</td>\\n<td>4.1.x</td>\\n<td>多端统一框架</td>\\n</tr>\\n<tr>\\n<td>UI 库</td>\\n<td>React</td>\\n<td>18.x</td>\\n<td>视图层</td>\\n</tr>\\n<tr>\\n<td>语言</td>\\n<td>TypeScript</td>\\n<td>5.x</td>\\n<td>类型安全</td>\\n</tr>\\n<tr>\\n<td>构建</td>\\n<td>Vite</td>\\n<td>4.x</td>\\n<td>编译打包</td>\\n</tr>\\n<tr>\\n<td>样式</td>\\n<td>Tailwind CSS</td>\\n<td>3.x</td>\\n<td>原子化 CSS</td>\\n</tr>\\n<tr>\\n<td>小程序适配</td>\\n<td>weapp-tailwindcss</td>\\n<td>4.x</td>\\n<td>小程序端 Tailwind rem→rpx 转换</td>\\n</tr>\\n<tr>\\n<td>状态管理</td>\\n<td>Zustand</td>\\n<td>5.x</td>\\n<td>轻量响应式 Store（Context 模式）</td>\\n</tr>\\n<tr>\\n<td>数据层</td>\\n<td>TanStack React Query</td>\\n<td>5.x</td>\\n<td>服务端状态管理</td>\\n</tr>\\n<tr>\\n<td>国际化</td>\\n<td>i18next + react-i18next</td>\\n<td>25.x / 16.x</td>\\n<td>多语言翻译</td>\\n</tr>\\n<tr>\\n<td>HTTP 客户端</td>\\n<td>Axios</td>\\n<td>1.x</td>\\n<td>REST 通信</td>\\n</tr>\\n<tr>\\n<td>代码高亮</td>\\n<td>highlight.js</td>\\n<td>11.x</td>\\n<td>语法着色</td>\\n</tr>\\n<tr>\\n<td>Markdown</td>\\n<td>marked</td>\\n<td>17.x</td>\\n<td>内容解析</td>\\n</tr>\\n<tr>\\n<td>数学公式</td>\\n<td>KaTeX</td>\\n<td>0.16.x</td>\\n<td>LaTeX 渲染</td>\\n</tr>\\n<tr>\\n<td>流程图</td>\\n<td>Mermaid</td>\\n<td>11.x</td>\\n<td>图表渲染</td>\\n</tr>\\n<tr>\\n<td>实时通信</td>\\n<td>SSE (fetch-event-source)</td>\\n<td>2.x</td>\\n<td>服务端推送</td>\\n</tr>\\n</tbody>\\n</table>"}');export{c as comp,r as data};
